    if (input == null || input.isEmpty()) {
        return "";
    }

    PhonemeBuilder builder = new PhonemeBuilder(this.phonemes);
    builder.setInput(input);

    if (this.nameType == NameType.SEPHARDIC) {
        builder = applyFinalRules(builder, this.finalRules);
    }

    if (this.ruleType == RuleType.RULES) {
        builder.build(languageSet);
    }

